/* Redo Utils, By BlackStar, Ver.0.3.0 */
(()=>{"use strict";const repalceText=text=>text.toString().replace(/['".]/g,"").replace(/^[$_]/,"").trim();const getRadioBtnName=text=>`[name='radiobutton-${repalceText(text)}']`;const getListBoxName=text=>`[name='listbox-${repalceText(text)}']`;const addListeners=(entity,getName,raw=true)=>{const parts=raw?entity.args.raw.split(" "):entity.args;$(document).on(":passagedisplay",(function(){for(const part of parts){const partName=getName(part);$(partName).change((()=>{const failRE=/^(?:do|for)$/;const passRE=/^(?:button|link(?:append|prepend|replace)?)$/;const closest=entity.contextFind((ctx=>failRE.test(ctx.name)||passRE.test(ctx.name)));if(closest&&failRE.test(closest.name)){return entity.error(`must not be used directly within macro <<${closest.name}>>`)}triggerEvent(":redo",document,{detail:{partName:partName}})}))}}))};Macro.add("changes",{handler(){addListeners(this,(part=>part),false)}});Macro.add("redo_radio",{handler(){addListeners(this,getRadioBtnName)}});Macro.add("redo_list",{handler(){addListeners(this,getListBoxName)}})})();
/* End Redo Utils */